<!-- 功能说明
管理端反馈处理核心页面，支持查看用户意见反馈列表、筛选反馈状态（未处理 / 已处理）、
标记已处理、回复反馈，核心对接反馈列表、更新反馈状态、回复反馈接口，为运营提供用户反馈处理工具。 -->

<template>
  <view class="feedback-manage-container">
    <!-- 页面头部 -->
    <view class="page-header">
      <text class="header-title">反馈管理</text>
    </view>

    <!-- 筛选区域 -->
    <view class="filter-container">
      <!-- 状态筛选 -->
      <picker 
        class="filter-picker"
        :range="statusList"
        :range-key="'label'"
        :value="filterForm.statusIndex"
        @change="handleFilterChange"
      >
        <view class="picker-content">
          <text>{{statusList[filterForm.statusIndex].label}}</text>
          <image src="/static/images/icon-arrow-down.png" class="picker-icon"></image>
        </view>
      </picker>

      <!-- 时间筛选 -->
      <view class="date-filter">
        <text class="filter-label">反馈时间：</text>
        <view class="date-picker-group">
          <picker 
            mode="date"
            :value="startDate"
            @change="handleStartDateChange"
            class="date-picker"
          >
            <view class="picker-text">{{startDate || '开始日期'}}</view>
          </picker>
          <text class="date-separator">-</text>
          <picker 
            mode="date"
            :value="endDate"
            @change="handleEndDateChange"
            class="date-picker"
          >
            <view class="picker-text">{{endDate || '结束日期'}}</view>
          </picker>
        </view>
      </view>

      <!-- 搜索区域 -->
      <view class="search-container">
        <image src="/static/images/icon-search.png" class="search-icon"></image>
        <input 
          class="search-input" 
          v-model="filterForm.keyword" 
          placeholder="请输入反馈内容/用户手机号搜索"
          @input="debounceSearch"
        ></input>
        <button class="reset-btn" @click="resetFilter" v-if="filterForm.keyword">重置</button>
      </view>
    </view>

    <!-- 反馈列表 -->
    <view class="feedback-list" v-if="feedbackList.length > 0">
      <view class="feedback-item" v-for="(item, index) in feedbackList" :key="item.id">
        <view class="feedback-header">
          <view class="user-info">
            <image :src="item.userAvatar || '/static/images/default-avatar.png'" class="user-avatar"></image>
            <view class="user-name-time">
              <text class="user-name">{{item.userNickname || '匿名用户'}}</text>
              <text class="feedback-time">{{formatTime(item.createTime)}}</text>
            </view>
          </view>
          <text class="feedback-status" :class="item.status === 'UNHANDLED' ? 'status-unhandled' : 'status-handled'">
            {{item.status === 'UNHANDLED' ? '未处理' : '已处理'}}
          </text>
        </view>
        <view class="feedback-content">
          <text class="content-text">{{item.content}}</text>
          <!-- 反馈图片 -->
          <view class="feedback-images" v-if="item.imageUrls && item.imageUrls.length > 0">
            <image 
              :src="img" 
              mode="aspectFill" 
              class="feedback-img"
              v-for="(img, imgIndex) in item.imageUrls"
              :key="imgIndex"
              @click="previewImage(item.imageUrls, imgIndex)"
            ></image>
          </view>
          <!-- 反馈回复 -->
          <view class="reply-content" v-if="item.replyContent">
            <text class="reply-label">管理员回复：</text>
            <text class="reply-text">{{item.replyContent}}</text>
            <text class="reply-time">{{formatTime(item.replyTime)}}</text>
          </view>
        </view>
        <view class="operation-group">
          <button class="oper-btn reply-btn" @click="showReplyModal(item, index)" v-if="item.status === 'UNHANDLED'">回复</button>
          <button class="oper-btn handle-btn" @click="markAsHandled(item.id, index)" v-if="item.status === 'UNHANDLED'">标记已处理</button>
        </view>
      </view>
    </view>

    <!-- 空列表状态 -->
    <view class="empty-list" v-else>
      <image src="/static/images/empty-feedback.png" class="empty-img"></image>
      <text class="empty-text">暂无符合条件的反馈记录</text>
    </view>

    <!-- 加载更多 -->
    <view class="load-more" v-if="isLoadingMore">
      <text class="load-text">加载中...</text>
    </view>

    <!-- 回复弹窗 -->
    <uni-modal 
      title="回复反馈" 
      :visible="replyModalVisible" 
      width="90%"
      @confirm="confirmReply"
      @cancel="hideReplyModal"
    >
      <view class="reply-form">
        <text class="form-label required">回复内容：</text>
        <textarea 
          class="reply-input" 
          v-model="replyContent"
          placeholder="请输入回复内容"
          maxlength="500"
          rows="5"
        ></textarea>
      </view>
    </uni-modal>
  </view>
</template>

<script setup>
import { ref } from 'vue';
import { onLoad, onShow } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const statusList = ref([
  { label: '全部状态', value: '' },
  { label: '未处理', value: 'UNHANDLED' },
  { label: '已处理', value: 'HANDLED' }
]);
const filterForm = ref({
  statusIndex: 0,
  keyword: '',
  pageNum: 1,
  pageSize: 10
});
const startDate = ref(''); // 开始日期
const endDate = ref(''); // 结束日期
const feedbackList = ref([]); // 反馈列表
const isLoadingMore = ref(false);
const hasMore = ref(true);
let searchTimer = null;

// 回复弹窗相关
const replyModalVisible = ref(false);
const replyContent = ref('');
const currentFeedback = ref(null);
const currentIndex = ref(-1);

// 页面加载获取反馈列表
onLoad(() => {
  if (!userStore.token || !['ADMIN', 'CUSTOMER_SERVICE'].includes(userStore.userInfo.role)) {
    uni.navigateTo({ url: '/pages/admin/login' });
    return;
  }
  getFeedbackList();
});

onShow(() => {
  filterForm.value.pageNum = 1;
  feedbackList.value = [];
  getFeedbackList();
});

// 获取反馈列表
const getFeedbackList = async () => {
  if (!hasMore.value || isLoadingMore.value) return;
  isLoadingMore.value = true;

  // 构造请求参数
  const params = {
    pageNum: filterForm.value.pageNum,
    pageSize: filterForm.value.pageSize,
    status: statusList.value[filterForm.statusIndex].value,
    keyword: filterForm.value.keyword.trim(),
    startDate: startDate.value,
    endDate: endDate.value
  };

  try {
    const res = await request({
      url: '/api/admin/feedback/list',
      method: 'GET',
      params
    });
    if (res.success) {
      const data = res.data.list || [];
      if (filterForm.value.pageNum === 1) {
        feedbackList.value = data;
      } else {
        feedbackList.value = [...feedbackList.value, ...data];
      }
      hasMore.value = filterForm.value.pageNum * filterForm.value.pageSize < res.data.total;
      filterForm.value.pageNum += 1;
    }
  } catch (error) {
    uni.showToast({ title: '反馈列表加载失败', icon: 'none' });
  } finally {
    isLoadingMore.value = false;
  }
};

// 筛选条件变更
const handleFilterChange = (e) => {
  filterForm.value.statusIndex = e.detail.value;
  filterForm.value.pageNum = 1;
  feedbackList.value = [];
  getFeedbackList();
};

// 开始日期选择
const handleStartDateChange = (e) => {
  startDate.value = e.detail.value;
  filterForm.value.pageNum = 1;
  feedbackList.value = [];
  getFeedbackList();
};

// 结束日期选择
const handleEndDateChange = (e) => {
  endDate.value = e.detail.value;
  filterForm.value.pageNum = 1;
  feedbackList.value = [];
  getFeedbackList();
};

// 搜索防抖
const debounceSearch = () => {
  clearTimeout(searchTimer);
  searchTimer = setTimeout(() => {
    filterForm.value.pageNum = 1;
    feedbackList.value = [];
    getFeedbackList();
  }, 500);
};

// 重置筛选
const resetFilter = () => {
  filterForm.value.keyword = '';
  filterForm.value.pageNum = 1;
  feedbackList.value = [];
  getFeedbackList();
};

// 格式化时间
const formatTime = (time) => {
  if (!time) return '';
  const date = new Date(time);
  return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')} ${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
};

// 预览反馈图片
const previewImage = (urls, current) => {
  uni.previewImage({
    current,
    urls
  });
};

// 显示回复弹窗
const showReplyModal = (item, index) => {
  currentFeedback.value = item;
  currentIndex.value = index;
  replyContent.value = '';
  replyModalVisible.value = true;
};

// 隐藏回复弹窗
const hideReplyModal = () => {
  replyModalVisible.value = false;
  currentFeedback.value = null;
  currentIndex.value = -1;
};

// 确认回复
const confirmReply = async () => {
  const content = replyContent.value.trim();
  if (!content) {
    uni.showToast({ title: '请输入回复内容', icon: 'none' });
    return;
  }

  try {
    const res = await request({
      url: '/api/admin/feedback/reply',
      method: 'POST',
      data: {
        feedbackId: currentFeedback.value.id,
        replyContent: content
      }
    });

    if (res.success) {
      uni.showToast({ title: '回复成功' });
      // 更新本地数据
      feedbackList.value[currentIndex.value] = {
        ...feedbackList.value[currentIndex.value],
        replyContent: content,
        replyTime: new Date().toISOString(),
        status: 'HANDLED'
      };
      hideReplyModal();
    } else {
      uni.showToast({ title: res.message || '回复失败', icon: 'none' });
    }
  } catch (error) {
    uni.showToast({ title: '网络异常，回复失败', icon: 'none' });
  }
};

// 标记已处理
const markAsHandled = async (feedbackId, index) => {
  uni.showModal({
    title: '提示',
    content: '确定要标记为已处理吗？',
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: '/api/admin/feedback/markHandled',
            method: 'PUT',
            data: { feedbackId }
          });
          if (res.success) {
            uni.showToast({ title: '标记成功' });
            feedbackList.value[index].status = 'HANDLED';
          } else {
            uni.showToast({ title: res.message || '标记失败', icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
        }
      }
    }
  });
};
</script>

